## 2. AVX-512 Memory Utilities (MASM-ready)

```cpp
// avx512_memory.asm - assemble with ml64 /c /Cp
; void avx512_zero_block(void* dst, size_t len)
.code
avx512_zero_block PROC FRAME
    push    rbx
    .pushreg rbx
    .endprolog

    mov     rbx, rcx        ; dst
    mov     rax, rdx        ; len
    vpxor   zmm0, zmm0, zmm0 ; Zero vector
    
    ; 512-byte loop
    cmp     rax, 512
    jb      @F
@Loop512:
    vmovdqu64 [rbx], zmm0
    vmovdqu64 [rbx+64], zmm0
    vmovdqu64 [rbx+128], zmm0
    vmovdqu64 [rbx+192], zmm0
    vmovdqu64 [rbx+256], zmm0
    vmovdqu64 [rbx+320], zmm0
    vmovdqu64 [rbx+384], zmm0
    vmovdqu64 [rbx+448], zmm0
    add     rbx, 512
    sub     rax, 512
    cmp     rax, 512
    jae     @Loop512

    ; 64-byte tail
@@:
    cmp     rax, 64
    jb      @F
@Loop64:
    vmovdqu64 [rbx], zmm0
    add     rbx, 64
    sub     rax, 64
    cmp     rax, 64
    jae     @Loop64

    ; Small tail
@@:
    test    rax, rax
    jz      @Done
    
    ; Use masked store for remainder
    mov     rcx, rax
    xor     rdx, rdx
    dec     rdx             ; 0xFFFF...
    shlx    rdx, rdx, rcx    ; mask
    not     rdx
    kmovq   k1, rdx
    vmovdqu8 [rbx]{k1}, zmm0

@Done:
    vzeroupper
    pop     rbx
    ret
avx512_zero_block ENDP

; uint32_t crc32_sse42(const void* data, size_t len, uint32_t seed)
crc32_sse42 PROC
    mov     r8, rdx         ; seed
    mov     rax, rcx        ; data
    mov     rcx, rdx        ; len
    mov     rdx, r8         ; crc = seed
    
    ; Process 8 bytes at a time
    cmp     rcx, 8
    jb      @ByteLoop
@QwordLoop:
    crc32   rax, qword ptr [rax]
    add     rax, 8
    sub     rcx, 8
    cmp     rcx, 8
    jae     @QwordLoop

    ; Remaining bytes
@ByteLoop:
    test    rcx, rcx
    jz      @Done
    crc32   eax, byte ptr [rax]
    inc     rax
    dec     rcx
    jmp     @ByteLoop
    
@Done:
    ret
crc32_sse42 ENDP

END
